import { Component, input, output, model, computed } from '@angular/core';

@Component({
  selector: 'app-counter',
  standalone: true,
  template: `
    <button (click)="dec()">-</button>
    <span>{{ value() }}</span>
    <button (click)="inc()">+</button>
  `,
})
export class CounterComponent {
  step = input(1);                 // optional input, default 1
  label = input.required<string>(); // required input, compile-time enforced
  value = model(0);                 // two-way: [(value)] in parent
  changed = output<number>();

  inc() { this.value.update(v => v + this.step()); this.changed.emit(this.value()); }
  dec() { this.value.update(v => v - this.step()); }
  display = computed(() => `${this.label()}: ${this.value()}`);
}

